"""Benchmarks for append-only dimension operations.

Uses the private join view (``schema.tablename``) generated by
pgcraft's ``AppendOnlyViewPlugin``.  INSTEAD OF triggers on the
private view handle INSERT, UPDATE, and DELETE.
"""

import pytest
from sqlalchemy import Column, String, text

from tests.benchmarks.conftest import (
    SCHEMA,
    BenchAppendOnly,
    build_metadata,
    create_all_from_metadata,
)

# The private view name generated by pgcraft for the append-only
# dimension is ``schema.tablename`` (same as the factory tablename).
_VIEW = f"{SCHEMA}.bm_ao"
_BIG_VIEW = f"{SCHEMA}.bm_ao_big"
_REV_VIEW = f"{SCHEMA}.bm_ao_rev"


@pytest.fixture(scope="module")
def _ao_tables(db_engine, bench_schema):  # noqa: ARG001
    meta, _ = build_metadata(BenchAppendOnly, "bm_ao", [Column("name", String)])
    with db_engine.connect() as conn:
        create_all_from_metadata(conn, meta)


@pytest.fixture(scope="module")
def _seeded_ao(db_engine, bench_schema):  # noqa: ARG001
    meta, _ = build_metadata(
        BenchAppendOnly,
        "bm_ao_big",
        [Column("name", String)],
    )
    with db_engine.connect() as conn:
        create_all_from_metadata(conn, meta)
        values = ", ".join(f"('item_{i}')" for i in range(10_000))
        conn.execute(text(f"INSERT INTO {_BIG_VIEW} (name) VALUES {values}"))
        conn.commit()


# -- single-row operations ------------------------------------------------


@pytest.mark.usefixtures("_ao_tables")
class TestAppendOnlySingleRow:
    def test_insert_single(self, benchmark, bench_conn):
        counter = {"i": 0}

        def do_insert():
            counter["i"] += 1
            bench_conn.execute(
                text(
                    f"INSERT INTO {_VIEW} (name) VALUES ('item_{counter['i']}')"
                )
            )
            bench_conn.commit()

        benchmark.pedantic(do_insert, rounds=10_000)

    def test_update_single(self, benchmark, bench_conn):
        bench_conn.execute(
            text(f"INSERT INTO {_VIEW} (name) VALUES ('to_update')")
        )
        bench_conn.commit()
        row_id = bench_conn.execute(
            text(f"SELECT id FROM {_VIEW} WHERE name = 'to_update' LIMIT 1")
        ).scalar()

        counter = {"i": 0}

        def do_update():
            counter["i"] += 1
            bench_conn.execute(
                text(
                    f"UPDATE {_VIEW}"
                    f" SET name = 'upd_{counter['i']}'"
                    f" WHERE id = {row_id}"
                )
            )
            bench_conn.commit()

        benchmark.pedantic(do_update, rounds=10_000)


# -- batch operations ------------------------------------------------------


@pytest.mark.usefixtures("_ao_tables")
class TestAppendOnlyBatch:
    def test_insert_batch_100(self, benchmark, bench_conn):
        counter = {"i": 0}

        def do_batch():
            counter["i"] += 1
            base = counter["i"] * 100
            values = ", ".join(f"('b100_{base + j}')" for j in range(100))
            bench_conn.execute(
                text(f"INSERT INTO {_VIEW} (name) VALUES {values}")
            )
            bench_conn.commit()

        benchmark.pedantic(do_batch, rounds=100)


# -- SELECT operations ----------------------------------------------------


@pytest.mark.usefixtures("_seeded_ao")
class TestAppendOnlySelect:
    def test_select_latest(self, benchmark, bench_conn):
        def do_select():
            bench_conn.execute(text(f"SELECT * FROM {_BIG_VIEW}")).fetchall()

        benchmark.pedantic(do_select, rounds=1_000)

    def test_select_after_many_updates(self, db_engine, benchmark, bench_conn):
        meta, _ = build_metadata(
            BenchAppendOnly,
            "bm_ao_rev",
            [Column("name", String)],
        )
        with db_engine.connect() as setup_conn:
            create_all_from_metadata(setup_conn, meta)
            setup_conn.execute(
                text(f"INSERT INTO {_REV_VIEW} (name) VALUES ('rev_entity')")
            )
            setup_conn.commit()
            row_id = setup_conn.execute(
                text(f"SELECT id FROM {_REV_VIEW} LIMIT 1")
            ).scalar()
            for i in range(100):
                setup_conn.execute(
                    text(
                        f"UPDATE {_REV_VIEW}"
                        f" SET name = 'rev_{i}'"
                        f" WHERE id = {row_id}"
                    )
                )
            setup_conn.commit()

        def do_select():
            bench_conn.execute(text(f"SELECT * FROM {_REV_VIEW}")).fetchall()

        benchmark.pedantic(do_select, rounds=1_000)
